<?php
/**
 * insert_furniture.php - Staff Insert Furniture Page
 * Allows staff to add new furniture products with material requirements
 * Furniture ID is auto-generated by the system
 */

require_once '../inc/config.php';
require_once '../inc/session.php';
require_once '../inc/functions.php';

// Check if user is logged in as staff
checkStaffRole();

$message = '';
$messageType = '';
$newFurnitureId = null;

// Get all materials for selection
$materials = getAllMaterials($conn);

// Handle form submission
if ($_SERVER['REQUEST_METHOD'] === 'POST') {
    $furnitureName = sanitizeInput($_POST['furniture_name'] ?? '');
    $furnitureDescription = sanitizeInput($_POST['furniture_description'] ?? '');
    $price = (float)($_POST['price'] ?? 0);
    $stockQuantity = (int)($_POST['stock_quantity'] ?? 0);
    $category = sanitizeInput($_POST['category'] ?? '');
    
    // Get selected materials
    $selectedMaterials = [];
    if (isset($_POST['materials']) && is_array($_POST['materials'])) {
        foreach ($_POST['materials'] as $materialId => $materialData) {
            if (isset($materialData['quantity']) && $materialData['quantity'] > 0) {
                $selectedMaterials[] = [
                    'id' => (int)$materialId,
                    'quantity' => (float)$materialData['quantity']
                ];
            }
        }
    }
    
    $errors = [];
    
    // Validate inputs
    if (empty($furnitureName)) {
        $errors[] = 'Furniture name is required.';
    } elseif (strlen($furnitureName) < 2) {
        $errors[] = 'Furniture name must be at least 2 characters.';
    }
    
    if (empty($furnitureDescription)) {
        $errors[] = 'Furniture description is required.';
    } elseif (strlen($furnitureDescription) < 10) {
        $errors[] = 'Please provide a more detailed description (at least 10 characters).';
    }
    
    if ($price <= 0) {
        $errors[] = 'Price must be greater than 0.';
    }
    
    if ($stockQuantity < 0) {
        $errors[] = 'Stock quantity cannot be negative.';
    }
    
    if (empty($category)) {
        $errors[] = 'Category is required.';
    }
    
    if (empty($selectedMaterials)) {
        $errors[] = 'At least one material is required for this furniture product.';
    }
    
    // Handle image upload
    $imageFile = $_FILES['furniture_image'] ?? null;
    if (!$imageFile || $imageFile['error'] !== UPLOAD_ERR_OK) {
        $errors[] = 'Furniture image is required.';
    } else {
        $allowedTypes = ['image/jpeg', 'image/png', 'image/gif', 'image/webp'];
        if (!in_array($imageFile['type'], $allowedTypes)) {
            $errors[] = 'Only JPG, PNG, GIF, and WEBP images are allowed.';
        }
        if ($imageFile['size'] > MAX_FILE_SIZE) {
            $errors[] = 'Image size must be less than 2MB.';
        }
    }
    
    // Handle view images (additional product views)
    $viewImages = $_FILES['view_images'] ?? [];
    $uploadedViews = [];

    if (empty($errors)) {
        $result = insertFurniture($conn, [
            'furniture_name' => $furnitureName,
            'furniture_description' => $furnitureDescription,
            'price' => $price,
            'stock_quantity' => $stockQuantity,
            'category' => $category,
            'materials' => $selectedMaterials
        ], $imageFile);

        if ($result['success']) {
            $newFurnitureId = $result['furniture_id'];

            // Process additional view images
            if (!empty($viewImages['name']) && is_array($viewImages['name'])) {
                $viewEntries = [];
                for ($i = 0; $i < count($viewImages['name']); $i++) {
                    if ($viewImages['error'][$i] === UPLOAD_ERR_OK && !empty($viewImages['name'][$i])) {
                        $ext = pathinfo($viewImages['name'][$i], PATHINFO_EXTENSION);
                        $viewName = time() . '_view' . ($i + 1) . '_' . uniqid() . '.' . $ext;
                        $dest = FURNITURE_IMAGE_UPLOAD_PATH . $viewName;
                        if (move_uploaded_file($viewImages['tmp_name'][$i], $dest)) {
                            $viewEntries[] = [
                                'path' => $viewName,
                                'sort_order' => count($viewEntries) + 2, // main img is sort 1
                                'is_primary' => 0
                            ];
                        }
                    }
                }
                if (!empty($viewEntries)) {
                    insertFurnitureImages($conn, $newFurnitureId, $viewEntries);
                }
            }

            // Save customization options
            $customCount = 0;
            if ($newFurnitureId) {
                $colorEntries = [];
                if (!empty($_POST['colors']['name'])) {
                    foreach ($_POST['colors']['name'] as $i => $cname) {
                        if (!empty(trim($cname))) {
                            $colorEntries[] = [
                                'name' => trim($cname),
                                'hex' => trim($_POST['colors']['hex'][$i] ?? '#cccccc'),
                                'additional_price' => floatval($_POST['colors']['price'][$i] ?? 0),
                                'sort_order' => count($colorEntries) + 1
                            ];
                        }
                    }
                }
                if (!empty($colorEntries)) { insertFurnitureColors($conn, $newFurnitureId, $colorEntries); $customCount += count($colorEntries); }

                $sizeEntries = [];
                if (!empty($_POST['sizes']['name'])) {
                    foreach ($_POST['sizes']['name'] as $i => $sname) {
                        if (!empty(trim($sname))) {
                            $sizeEntries[] = [
                                'name' => trim($sname),
                                'dimensions' => trim($_POST['sizes']['dim'][$i] ?? ''),
                                'additional_price' => floatval($_POST['sizes']['price'][$i] ?? 0),
                                'sort_order' => count($sizeEntries) + 1
                            ];
                        }
                    }
                }
                if (!empty($sizeEntries)) { insertFurnitureSizes($conn, $newFurnitureId, $sizeEntries); $customCount += count($sizeEntries); }

                $accEntries = [];
                if (!empty($_POST['accessories']['name'])) {
                    foreach ($_POST['accessories']['name'] as $i => $aname) {
                        if (!empty(trim($aname))) {
                            $accEntries[] = [
                                'name' => trim($aname),
                                'description' => trim($_POST['accessories']['desc'][$i] ?? ''),
                                'additional_price' => floatval($_POST['accessories']['price'][$i] ?? 0),
                                'sort_order' => count($accEntries) + 1
                            ];
                        }
                    }
                }
                if (!empty($accEntries)) { insertFurnitureAccessories($conn, $newFurnitureId, $accEntries); $customCount += count($accEntries); }
            }

            $message = $result['message'] . (!empty($viewEntries) ? ' (' . count($viewEntries) . ' additional views saved.)' : '') . ($customCount > 0 ? ' (' . $customCount . ' customization options saved.)' : '');
            $messageType = 'success';

            // Clear form
            $_POST = [];
        } else {
            $message = $result['message'];
            $messageType = 'danger';
        }
    } else {
        $message = implode('<br>', $errors);
        $messageType = 'danger';
    }
}

// Get all furniture for display
$allFurniture = getAllFurniture($conn);

// Fetch product view images for the list
$listImages = [];
$imgSql = "SELECT FurnitureID, ImagePath, IsPrimary FROM FurnitureImage ORDER BY SortOrder ASC";
$imgResult = mysqli_query($conn, $imgSql);
while ($img = mysqli_fetch_assoc($imgResult)) {
    if (!isset($listImages[$img['FurnitureID']])) {
        $listImages[$img['FurnitureID']] = [];
    }
    $listImages[$img['FurnitureID']][] = $img;
}
