    <script src="../assets/js/validation.js"></script>
    <script>
        function toggleMaterialInput(materialId, isChecked) {
            const quantityInput = document.getElementById(`material_quantity_${materialId}`);
            if (quantityInput) {
                quantityInput.disabled = !isChecked;
                if (!isChecked) {
                    quantityInput.value = '';
                }
            }
        }
        
        // Image preview
        document.getElementById('furniture_image')?.addEventListener('change', function(e) {
            const file = e.target.files[0];
            const preview = document.getElementById('image_preview');
            if (file && preview) {
                const reader = new FileReader();
                reader.onload = function(event) {
                    preview.src = event.target.result;
                    preview.style.display = 'block';
                };
                reader.readAsDataURL(file);
            }
        });

        // View image previews
        function previewViewImage(input, index) {
            const row = input.closest('.view-image-row');
            const preview = row ? row.querySelector('.view-preview') : null;
            if (input.files && input.files[0] && preview) {
                const reader = new FileReader();
                reader.onload = function(e) {
                    preview.src = e.target.result;
                    preview.style.display = 'block';
                };
                reader.readAsDataURL(input.files[0]);
            }
        }

        // Add customization row
        function addCustomRow(containerId, type) {
            const container = document.getElementById(containerId);
            if (!container) return;
            const div = document.createElement('div');
            div.className = 'custom-row';
            div.style.cssText = 'display:flex;gap:6px;margin-bottom:4px;';
            let inputs = '';
            if (type === 'color') {
                inputs = '<input type=\"text\" name=\"colors[name][]\" placeholder=\"Color name\" class=\"form-control\" style=\"flex:2;\">' +
                    '<input type=\"text\" name=\"colors[hex][]\" placeholder=\"#hex\" class=\"form-control\" style=\"flex:1;max-width:90px;\">' +
                    '<input type=\"number\" name=\"colors[price][]\" placeholder=\"+$\" class=\"form-control\" style=\"flex:1;max-width:70px;\" step=\"0.01\" min=\"0\" value=\"0\">';
            } else if (type === 'size') {
                inputs = '<input type=\"text\" name=\"sizes[name][]\" placeholder=\"Size name\" class=\"form-control\" style=\"flex:2;\">' +
                    '<input type=\"text\" name=\"sizes[dim][]\" placeholder=\"Dimensions\" class=\"form-control\" style=\"flex:2;\">' +
                    '<input type=\"number\" name=\"sizes[price][]\" placeholder=\"+$\" class=\"form-control\" style=\"flex:1;max-width:70px;\" step=\"0.01\" min=\"0\" value=\"0\">';
            } else if (type === 'accessory') {
                inputs = '<input type=\"text\" name=\"accessories[name][]\" placeholder=\"Name\" class=\"form-control\" style=\"flex:2;\">' +
                    '<input type=\"text\" name=\"accessories[desc][]\" placeholder=\"Description\" class=\"form-control\" style=\"flex:3;\">' +
                    '<input type=\"number\" name=\"accessories[price][]\" placeholder=\"+$\" class=\"form-control\" style=\"flex:1;max-width:70px;\" step=\"0.01\" min=\"0\" value=\"0\">';
            }
            div.innerHTML = inputs + '<button type=\"button\" onclick=\"this.parentElement.remove()\" style=\"background:none;border:none;color:var(--danger);cursor:pointer;font-size:1.1rem;padding:0 4px;\" title=\"Remove\">✕</button>';
            container.appendChild(div);
        }
    </script>
</body>
</html>